import React, { useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { CartProvider } from './context/CartContext';
import { UIProvider } from './context/UIContext';
import Header from './components/Header';
import ShopPage from './pages/ShopPage';
import ProductPage from './pages/ProductPage';
import AdminPage from './pages/AdminPage';
import LoginPage from './pages/LoginPage';
import CartModal from './components/CartModal';
import CheckoutModal from './components/CheckoutModal';
import { useUI } from './hooks/useUI';

const ContactPage = () => (
    <div className="text-center py-20">
        <h1 className="text-4xl font-serif font-bold mb-4">Contactez-nous</h1>
        <p className="text-secondary">Pour toute question, veuillez nous envoyer un email à contact@mercadonamaroc.com</p>
        <Link to="/" className="mt-8 inline-block text-primary font-semibold border-b-2 border-primary pb-1">Retour à l'accueil</Link>
    </div>
);

const UIEffects: React.FC = () => {
    const { closeSearch } = useUI();
    const location = useLocation();

    useEffect(() => {
        closeSearch();
    }, [location.pathname, closeSearch]);

    return null;
}


const App: React.FC = () => {
  return (
    <UIProvider>
      <CartProvider>
        <HashRouter>
          <UIEffects />
          <div className="flex flex-col min-h-screen font-sans">
            <Header />
            <main className="flex-grow w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 md:py-16">
              <Routes>
                <Route path="/" element={<ShopPage category="all" />} />
                <Route path="/packs" element={<ShopPage category="pack" />} />
                <Route path="/sur-commande" element={<ShopPage category="sur-commande" />} />
                <Route path="/contact" element={<ContactPage />} />
                <Route path="/product/:id" element={<ProductPage />} />
                <Route path="/admin" element={<AdminPage />} />
                <Route path="/login" element={<LoginPage />} />
              </Routes>
            </main>
            <footer className="bg-white py-8 border-t border-gray-200">
                <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center text-secondary text-sm">
                    <p>&copy; {new Date().getFullYear()} PRODUITS MERCADONA MAROC. Tous droits réservés.</p>
                    <Link to="/admin" className="mt-2 inline-block opacity-0 hover:opacity-100 transition-opacity">Panel Admin</Link>
                </div>
            </footer>
          </div>
          <CartModal />
          <CheckoutModal />
        </HashRouter>
      </CartProvider>
    </UIProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../services/firebase';
import { useNavigate } from 'react-router-dom';

const LoginPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signInWithEmailAndPassword(auth, email, password);
      navigate('/admin');
    } catch (err: any) {
      setError('Identifiants invalides. Veuillez réessayer.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-md mx-auto py-20 px-4">
      <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
        <h1 className="text-3xl font-serif font-bold text-center mb-8">Connexion Admin</h1>
        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
            <input
              type="email"
              required
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-primary focus:border-primary"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Mot de passe</label>
            <input
              type="password"
              required
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-primary focus:border-primary"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          {error && <p className="text-red-500 text-sm">{error}</p>}
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-primary text-white font-bold py-3 rounded-md hover:bg-gray-800 transition-colors disabled:bg-gray-400"
          >
            {loading ? 'Connexion...' : 'Se connecter'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { collection, getDocs, addDoc, updateDoc, deleteDoc, doc } from 'firebase/firestore';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { db, auth } from '../services/firebase';
import { Product } from '../types';
import { useNavigate } from 'react-router-dom';
import Spinner from '../components/Spinner';

const AdminPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<any>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    image: '',
    salePrice: 0,
    stock: 0,
    isOrderBased: false,
    category: ''
  });

  const navigate = useNavigate();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) {
        navigate('/login');
      } else {
        setUser(currentUser);
        fetchProducts();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const querySnapshot = await getDocs(collection(db, 'products'));
      const list = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Product));
      setProducts(list.sort((a, b) => a.name.localeCompare(b.name)));
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await signOut(auth);
    navigate('/login');
  };

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData({
        name: product.name,
        description: product.description || '',
        image: product.image,
        salePrice: product.salePrice,
        stock: product.stock || 0,
        isOrderBased: product.isOrderBased || false,
        category: product.category || ''
      });
    } else {
      setEditingProduct(null);
      setFormData({
        name: '',
        description: '',
        image: '',
        salePrice: 0,
        stock: 0,
        isOrderBased: false,
        category: ''
      });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const dataToSave = {
        ...formData,
        // On sauvegarde le stock dans plusieurs champs pour la compatibilité avec l'ancien système
        'stock': Number(formData.stock),
        'STOCK INITIAL': Number(formData.stock),
        'stockInitial': Number(formData.stock),
      };

      if (editingProduct) {
        await updateDoc(doc(db, 'products', editingProduct.id), dataToSave);
      } else {
        await addDoc(collection(db, 'products'), dataToSave);
      }
      setIsModalOpen(false);
      fetchProducts();
    } catch (err) {
      alert("Erreur lors de l'enregistrement");
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Voulez-vous vraiment supprimer ce produit ?")) {
      await deleteDoc(doc(db, 'products', id));
      fetchProducts();
    }
  };

  if (loading && !user) return <Spinner />;

  return (
    <div className="py-10">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="text-4xl font-serif font-bold">Tableau de Bord</h1>
          <p className="text-secondary">Gérez votre inventaire et vos produits.</p>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={() => handleOpenModal()} 
            className="bg-primary text-white px-6 py-2 rounded-md hover:bg-gray-800 transition-colors font-bold"
          >
            + Nouveau Produit
          </button>
          <button 
            onClick={handleLogout} 
            className="border border-red-500 text-red-500 px-6 py-2 rounded-md hover:bg-red-50 transition-colors"
          >
            Déconnexion
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Produit</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Catégorie</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Prix</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Stock</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {products.map(p => (
              <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 flex items-center gap-4">
                  <img src={p.image} alt={p.name} className="w-12 h-12 object-contain bg-gray-50 rounded" />
                  <div>
                    <p className="font-semibold text-primary">{p.name}</p>
                    {p.isOrderBased && <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full uppercase">Sur Commande</span>}
                  </div>
                </td>
                <td className="px-6 py-4 text-sm text-secondary uppercase tracking-tight">{p.category || 'N/A'}</td>
                <td className="px-6 py-4 font-medium">{p.salePrice.toFixed(2)} DH</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded text-xs font-bold ${Number(p.stock) > 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {p.stock} en stock
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex gap-3">
                    <button onClick={() => handleOpenModal(p)} className="text-blue-500 hover:text-blue-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="text-red-500 hover:text-red-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden animate-fade-in-scale">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-primary text-white">
              <h2 className="text-xl font-bold">{editingProduct ? 'Modifier le Produit' : 'Ajouter un Produit'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-white hover:opacity-70 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[80vh] overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Nom du produit</label>
                  <input type="text" required className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Catégorie</label>
                  <input type="text" placeholder="Ex: pack, visage, cheveux" className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Description</label>
                <textarea rows={3} className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Prix (DH)</label>
                  <input type="number" required step="0.01" className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Stock Initial</label>
