interface CartContextType {
  cartItems: CartItem[];
  addToCart: (product: Product, quantity?: number) => void;
  updateQuantity: (productId: string, quantity: number) => void;
  removeFromCart: (productId: string) => void;
  clearCart: () => void;
  cartCount: number;
  cartTotal: number;
}

export const CartContext = createContext<CartContextType | undefined>(undefined);

export const CartProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);

  useEffect(() => {
    try {
      const storedCart = localStorage.getItem('cart');
      if (storedCart) {
        setCartItems(JSON.parse(storedCart));
      }
    } catch (error) {
      console.error("Failed to parse cart from localStorage", error);
      localStorage.removeItem('cart');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('cart', JSON.stringify(cartItems));
  }, [cartItems]);

  const addToCart = useCallback((product: Product, quantity = 1) => {
    setCartItems(prevItems => {
      const existingItem = prevItems.find(item => item.id === product.id);
      if (existingItem) {
        return prevItems.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prevItems, { ...product, quantity }];
    });
  }, []);

  const updateQuantity = useCallback((productId: string, quantity: number) => {
    setCartItems(prevItems => {
      if (quantity <= 0) {
        return prevItems.filter(item => item.id !== productId);
      }
      return prevItems.map(item =>
        item.id === productId ? { ...item, quantity } : item
      );
    });
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCartItems(prevItems => prevItems.filter(item => item.id !== productId));
  }, []);

  const clearCart = useCallback(() => {
    setCartItems([]);
  }, []);

  const cartCount = cartItems.reduce((count, item) => count + item.quantity, 0);
  const cartTotal = cartItems.reduce((total, item) => total + (Number(item.salePrice) || 0) * item.quantity, 0);

  return (
    <CartContext.Provider value={{ cartItems, addToCart, updateQuantity, removeFromCart, clearCart, cartCount, cartTotal }}>
      {children}
    </CartContext.Provider>
  );
};

import React, { useState, useEffect } from 'react';
import { collection, getDocs, addDoc, updateDoc, deleteDoc, doc } from 'firebase/firestore';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { db, auth } from '../services/firebase';
import { Product } from '../types';
import { useNavigate } from 'react-router-dom';
import Spinner from '../components/Spinner';

const ADMIN_EMAIL = "elhajiauto@gmail.com";

const AdminPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<any>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    image: '',
    salePrice: 0,
    stock: 0,
    isOrderBased: false,
    category: ''
  });

  const navigate = useNavigate();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) {
        navigate('/login');
      } else {
        setUser(currentUser);
        fetchProducts();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const querySnapshot = await getDocs(collection(db, 'elhauto_products'));
      const list = querySnapshot.docs.map(doc => {
          const data = doc.data();
          const salePriceValue = Number(data['salePrice'] ?? data['SALE PRICE'] ?? data['price'] ?? 0);
          return { 
            id: doc.id, 
            ...data, 
            salePrice: salePriceValue 
          } as Product;
      });
      setProducts(list.sort((a, b) => a.name.localeCompare(b.name)));
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await signOut(auth);
    navigate('/login');
  };

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData({
        name: product.name,
        description: product.description || '',
        image: product.image,
        salePrice: product.salePrice,
        stock: product.stock || 0,
        isOrderBased: product.isOrderBased || false,
        category: product.category || ''
      });
    } else {
      setEditingProduct(null);
      setFormData({
        name: '',
        description: '',
        image: '',
        salePrice: 0,
        stock: 0,
        isOrderBased: false,
        category: ''
      });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (user?.email !== ADMIN_EMAIL) {
      alert("Accès refusé. Seul " + ADMIN_EMAIL + " peut modifier les produits.");
      return;
    }
    try {
      const dataToSave = {
        ...formData,
        'stock': Number(formData.stock),
        'STOCK INITIAL': Number(formData.stock),
        'stockInitial': Number(formData.stock),
      };

      if (editingProduct) {
        await updateDoc(doc(db, 'elhauto_products', editingProduct.id), dataToSave);
      } else {
        await addDoc(collection(db, 'elhauto_products'), dataToSave);
      }
      setIsModalOpen(false);
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Erreur lors de l'enregistrement. Vérifiez vos permissions.");
    }
  };

  const handleDelete = async (id: string) => {
    if (user?.email !== ADMIN_EMAIL) {
      alert("Accès refusé.");
      return;
    }
    if (window.confirm("Voulez-vous vraiment supprimer ce produit ?")) {
      await deleteDoc(doc(db, 'elhauto_products', id));
      fetchProducts();
    }
  };

  if (loading && !user) return <Spinner />;

  return (
    <div className="py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h1 className="text-4xl font-serif font-bold">Tableau de Bord</h1>
          <p className="text-secondary">Connecté en tant que : <span className="font-bold text-primary">{user?.email}</span></p>
          {user?.email !== ADMIN_EMAIL && (
            <p className="text-red-500 text-xs font-bold uppercase mt-1">Mode Lecture Seule (Accès Admin requis)</p>
          )}
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <button 
            onClick={() => handleOpenModal()} 
            className="flex-grow md:flex-grow-0 bg-primary text-white px-6 py-2 rounded-md hover:bg-gray-800 transition-colors font-bold"
          >
            + Nouveau Produit
          </button>
          <button 
            onClick={handleLogout} 
            className="border border-red-500 text-red-500 px-6 py-2 rounded-md hover:bg-red-50 transition-colors"
          >
            Déconnexion
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[600px]">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Produit</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Catégorie</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Prix</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Stock</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {products.map(p => (
              <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 flex items-center gap-4">
                  <img src={p.image} alt={p.name} className="w-12 h-12 object-contain bg-gray-50 rounded" />
                  <div>
                    <p className="font-semibold text-primary">{p.name}</p>
                    {p.isOrderBased && <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full uppercase">Sur Commande</span>}
                  </div>
                </td>
                <td className="px-6 py-4 text-sm text-secondary uppercase tracking-tight">{p.category || 'N/A'}</td>
                <td className="px-6 py-4 font-medium">{(p.salePrice || 0).toFixed(2)} DH</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded text-xs font-bold ${Number(p.stock) > 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {p.stock} en stock
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex gap-3">
                    <button onClick={() => handleOpenModal(p)} className="text-blue-500 hover:text-blue-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="text-red-500 hover:text-red-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden animate-fade-in-scale">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-primary text-white">
              <h2 className="text-xl font-bold">{editingProduct ? 'Modifier le Produit' : 'Ajouter un Produit'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-white hover:opacity-70 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[80vh] overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Nom du produit</label>
                  <input type="text" required className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Catégorie</label>
                  <input type="text" placeholder="Ex: pack, visage, cheveux" className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Description</label>
                <textarea rows={3} className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Prix (DH)</label>
                  <input type="number" required step="0.01" className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Stock Initial</label>
                  <input type="number" required className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.stock} onChange={e => setFormData({...formData, stock: Number(e.target.value)})} />
                </div>
                <div className="flex items-center pt-6">
                  <label className="flex items-center gap-3 cursor-pointer">
                    <input type="checkbox" className="h-5 w-5 rounded border-gray-300 text-primary focus:ring-primary" checked={formData.isOrderBased} onChange={e => setFormData({...formData, isOrderBased: e.target.checked})} />
                    <span className="text-sm font-bold text-gray-700 uppercase tracking-tighter">Sur Commande</span>
                  </label>
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">URL de l'image</label>
                <input type="text" required className="w-full px-4 py-2 border border-gray-200 rounded-md" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} />
                {formData.image && <img src={formData.image} alt="Preview" className="mt-2 h-20 w-20 object-contain border border-gray-100 rounded" />}
              </div>

              <button type="submit" className="w-full bg-primary text-white font-bold py-4 rounded-md hover:bg-gray-800 transition-colors">
                {editingProduct ? 'Mettre à jour' : 'Ajouter le produit'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, getDocs } from 'firebase/firestore';
import { db } from '../services/firebase';
import { Product } from '../types';
import ProductCard from '../components/ProductCard';
import Spinner from '../components/Spinner';
import { useUI } from '../hooks/useUI';

interface ShopPageProps {
  category?: 'all' | 'pack' | 'sur-commande';
}

const ShopPage: React.FC<ShopPageProps> = ({ category = 'all' }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const { searchTerm } = useUI();

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        setLoading(true);
        const productsCollection = collection(db, 'products');
        const productSnapshot = await getDocs(productsCollection);
        const productsList = productSnapshot.docs.map(doc => {
          const data = doc.data();

          // Mapping intelligent du stock basé sur la capture d'écran (availableStock est prioritaire)
          const rawStock = data['availableStock'] ?? data['stock'] ?? data['initialStock'] ?? 0;
          const stockValue = isNaN(Number(rawStock)) ? 0 : Number(rawStock);

          const salePriceValue = Number(data['salePrice'] ?? data['SALE PRICE'] ?? data['price'] ?? 0);

          return {
            id: doc.id,
            ...data,
            salePrice: salePriceValue,
            stock: stockValue,
            isOrderBased: data['isOrderBased'] ?? false,
          } as Product
        });
        setProducts(productsList);
      } catch (err: any) {
        setError('Erreur de chargement des produits: ' + err.message);
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  const filteredProducts = useMemo(() => {
    let filtered = products;

    if (category === 'pack') {
      filtered = filtered.filter(p => 
        (p.name?.toLowerCase().includes('pack') || 
         (p.category && p.category.toLowerCase() === 'pack')) &&
        !p.isOrderBased
      );
    } else if (category === 'sur-commande') {
      filtered = filtered.filter(p => p.isOrderBased === true);
    } else {
      filtered = filtered.filter(p => !p.isOrderBased);
    }

    if (searchTerm.trim()) {
      filtered = filtered.filter(p => 
        p.name?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    filtered.sort((a, b) => (a.name || "").localeCompare(b.name || ""));

    return filtered;
  }, [products, searchTerm, category]);

  const getPageTitle = () => {
    if (searchTerm) return `Résultats pour "${searchTerm}"`;
    switch (category) {
      case 'pack': return 'Nos Packs';
      case 'sur-commande': return 'Sur Commande';
      default: return 'Nos Produits';
    }
  };

  if (loading) return <Spinner />;
  if (error) return <p className="text-center text-red-500">{error}</p>;

  return (
    <div>
      <h1 className="text-4xl md:text-5xl font-serif font-bold mb-12 text-center text-primary">
        {getPageTitle()}
      </h1>

      {products.length === 0 && !loading ? (
        <p className="text-center text-secondary">Aucun produit disponible pour le moment.</p>
      ) : (
        <>
          {filteredProducts.length === 0 ? (
            <p className="text-center text-secondary">Aucun produit ne correspond à vos critères.</p>
          ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-8">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} />
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default ShopPage;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '../services/firebase';
import { Product } from '../types';
import Spinner from '../components/Spinner';
import { useCart } from '../hooks/useCart';
import { useUI } from '../hooks/useUI';
import RelatedProducts from '../components/RelatedProducts';

const ProductPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [product, setProduct] = useState<Product | null>(null);
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const { addToCart } = useCart();
  const { openCart, openCheckout } = useUI();

  useEffect(() => {
    setLoading(true);
    setQuantity(1);
    const fetchProduct = async () => {
      if (!id) {
        setError("ID de produit manquant.");
        setLoading(false);
        return;
      }
      try {
        const productDocRef = doc(db, 'products', id);
        const productSnap = await getDoc(productDocRef);

        if (productSnap.exists()) {
          const data = productSnap.data();

          const rawStock = data['availableStock'] ?? data['stock'] ?? data['initialStock'] ?? 0;
          const stockValue = isNaN(Number(rawStock)) ? 0 : Number(rawStock);

          const salePriceValue = Number(data['salePrice'] ?? data['SALE PRICE'] ?? data['price'] ?? 0);

          setProduct({ 
            id: productSnap.id, 
            ...data,
            salePrice: salePriceValue,
            stock: stockValue,
          } as Product);
        } else {
          setError('Produit non trouvé.');
        }
      } catch (err: any) {
        setError('Erreur de chargement du produit: ' + err.message);
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  const handleBuyNow = () => {
    if (product) {
      addToCart(product, quantity);
      openCheckout();
    }
  };

  const handleAddToCart = () => {
    if (product) {
      addToCart(product, quantity);
      openCart();
    }
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement, Event>) => {
    e.currentTarget.src = `https://picsum.photos/seed/${id}/600/600`;
  };

  const handleQuantityChange = (amount: number) => {
    setQuantity(prev => Math.max(1, prev + amount));
  };

  if (loading) return <Spinner />;
  if (error) return <p className="text-center text-red-500">{error}</p>;
  if (!product) return <p className="text-center text-secondary">Produit introuvable.</p>;

  const isOutOfStock = product.stock !== undefined && product.stock <= 0;

  return (
    <div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10 md:gap-16 items-start">
            <div className="bg-accent rounded-lg p-4 flex justify-center items-center aspect-square md:sticky md:top-28">
                <img 
                    src={product.image || `https://picsum.photos/seed/${id}/600/600`}
                    alt={product.name} 
                    onError={handleImageError}
                    className={`w-full max-w-md h-auto object-contain ${isOutOfStock ? 'opacity-60' : ''}`}
                />
            </div>
            <div className="flex flex-col space-y-6 pt-4">
                <p className="text-sm font-semibold tracking-widest text-secondary uppercase">PRODUITS MERCADONA MAROC</p>
                <h1 className="text-4xl md:text-5xl font-serif font-bold text-primary capitalize">{product.name}</h1>
                <p className="text-3xl font-semibold text-primary">{(product.salePrice || 0).toFixed(2)} DH</p>

                {isOutOfStock && (
                    <div className="p-3 bg-red-50 border border-red-200 rounded-md text-center">
                        <p className="font-semibold text-red-700">Ce produit est actuellement en rupture de stock.</p>
                    </div>
                )}

                <p className="text-secondary leading-relaxed text-sm">
                  {product.description || 'Frais d\'expédition calculés à l\'étape du paiement.'}
                </p>

                <div className="flex items-center space-x-4">
                    <label htmlFor="quantity" className="font-semibold text-sm">Quantité</label>
                    <div className="flex items-center border border-gray-300 rounded-md">
                        <button onClick={() => handleQuantityChange(-1)} disabled={isOutOfStock} className="px-3 py-2 text-gray-600 hover:bg-gray-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed" aria-label="Decrease quantity">-</button>
                        <span className="px-4 text-base w-12 text-center" id="quantity">{quantity}</span>
                        <button onClick={() => handleQuantityChange(1)} disabled={isOutOfStock} className="px-3 py-2 text-gray-600 hover:bg-gray-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed" aria-label="Increase quantity">+</button>
                    </div>
                </div>

                <div className="flex flex-col space-y-4 pt-4">
                    <button onClick={handleAddToCart} disabled={isOutOfStock} className="w-full border border-primary text-primary font-bold py-3 px-6 rounded-md transition-colors duration-300 hover:bg-primary hover:text-white disabled:bg-gray-200 disabled:text-gray-500 disabled:border-gray-200 disabled:cursor-not-allowed">
                        Ajouter au panier
                    </button>
                    <button onClick={handleBuyNow} disabled={isOutOfStock} className="w-full bg-primary text-white font-bold py-3 px-6 rounded-md transition-colors duration-300 hover:bg-gray-800 disabled:bg-gray-400 disabled:cursor-not-allowed">
                        Acheter maintenant
                    </button>
                </div>
            </div>
        </div>

        {id && <RelatedProducts currentProductId={id} />}
    </div>
  );
};

export default ProductPage;

import React, { useState, useEffect } from 'react';
import { collection, getDocs, addDoc, updateDoc, deleteDoc, doc, serverTimestamp } from 'firebase/firestore';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { db, auth } from '../services/firebase';
import { Product } from '../types';
import { useNavigate } from 'react-router-dom';
import Spinner from '../components/Spinner';

const ADMIN_EMAIL = "elhajiauto@gmail.com";

const AdminPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<any>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    image: '',
    salePrice: 0,
    availableStock: 0,
    isOrderBased: false,
    category: ''
  });

  const navigate = useNavigate();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) {
        navigate('/login');
      } else {
        setUser(currentUser);
        fetchProducts();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const querySnapshot = await getDocs(collection(db, 'products'));
      const list = querySnapshot.docs.map(doc => {
          const data = doc.data();
          const salePriceValue = Number(data['salePrice'] ?? data['SALE PRICE'] ?? data['price'] ?? 0);
          const rawStock = data['availableStock'] ?? data['stock'] ?? 0;
          const stockValue = isNaN(Number(rawStock)) ? 0 : Number(rawStock);

          return { 
            id: doc.id, 
            ...data, 
            salePrice: salePriceValue,
            stock: stockValue 
          } as Product;
      });
      setProducts(list.sort((a, b) => (a.name || "").localeCompare(b.name || "")));
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await signOut(auth);
    navigate('/login');
  };

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setEditingProduct(product);
      setFormData({
        name: product.name || '',
        description: product.description || '',
        image: product.image || '',
        salePrice: product.salePrice || 0,
        availableStock: product.stock || 0,
        isOrderBased: product.isOrderBased || false,
        category: product.category || ''
      });
    } else {
      setEditingProduct(null);
      setFormData({
        name: '',
        description: '',
        image: '',
        salePrice: 0,
        availableStock: 0,
        isOrderBased: false,
        category: ''
      });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (user?.email !== ADMIN_EMAIL) {
      alert("Accès refusé. Seul " + ADMIN_EMAIL + " peut modifier les produits.");
      return;
    }
    try {
      const dataToSave = {
        name: formData.name,
        description: formData.description,
        image: formData.image,
        salePrice: Number(formData.salePrice),
        availableStock: Number(formData.availableStock),
        initialStock: Number(formData.availableStock), // Synchronisé pour les nouveaux produits
        stock: Number(formData.availableStock), // Backup field
        isOrderBased: formData.isOrderBased,
        category: formData.category,
        updatedAt: serverTimestamp(),
        createdBy: user.email
      };

      if (editingProduct) {
        await updateDoc(doc(db, 'products', editingProduct.id), dataToSave);
      } else {
        await addDoc(collection(db, 'products'), {
          ...dataToSave,
          createdAt: serverTimestamp()
        });
      }
      setIsModalOpen(false);
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Erreur lors de l'enregistrement. Vérifiez vos permissions.");
    }
  };

  const handleDelete = async (id: string) => {
    if (user?.email !== ADMIN_EMAIL) {
      alert("Accès refusé.");
      return;
    }
    if (window.confirm("Voulez-vous vraiment supprimer ce produit ?")) {
      await deleteDoc(doc(db, 'products', id));
      fetchProducts();
    }
  };

  if (loading && !user) return <Spinner />;

  return (
    <div className="py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <h1 className="text-4xl font-serif font-bold">Admin Panel - Mercadona</h1>
          <p className="text-secondary">Session : <span className="font-bold text-primary">{user?.email}</span></p>
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <button 
            onClick={() => handleOpenModal()} 
            className="flex-grow md:flex-grow-0 bg-primary text-white px-6 py-2 rounded-md hover:bg-gray-800 transition-colors font-bold"
          >
            + Nouveau Produit
          </button>
          <button 
            onClick={handleLogout} 
            className="border border-red-500 text-red-500 px-6 py-2 rounded-md hover:bg-red-50 transition-colors"
          >
            Déconnexion
          </button>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[600px]">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Produit</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Catégorie</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Prix</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Stock Dispo</th>
              <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {products.map(p => (
              <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 flex items-center gap-4">
                  <img src={p.image} alt={p.name} className="w-12 h-12 object-contain bg-gray-50 rounded" />
                  <div>
                    <p className="font-semibold text-primary">{p.name}</p>
                    {p.isOrderBased && <span className="text-[10px] bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full uppercase">Sur Commande</span>}
                  </div>
                </td>
                <td className="px-6 py-4 text-sm text-secondary uppercase tracking-tight">{p.category || 'N/A'}</td>
                <td className="px-6 py-4 font-medium">{(p.salePrice || 0).toFixed(2)} DH</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded text-xs font-bold ${Number(p.stock) > 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {p.stock} unités
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex gap-3">
                    <button onClick={() => handleOpenModal(p)} className="text-blue-500 hover:text-blue-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="text-red-500 hover:text-red-700">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden animate-fade-in-scale">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-primary text-white">
              <h2 className="text-xl font-bold">{editingProduct ? 'Modifier le Produit' : 'Ajouter un Produit'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-white hover:opacity-70 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[80vh] overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Nom du produit</label>
                  <input type="text" required className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Catégorie</label>
                  <input type="text" placeholder="Ex: pack, visage, cheveux" className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Description</label>
                <textarea rows={3} className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Prix de vente (DH)</label>
                  <input type="number" required step="0.01" className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">Stock Disponible</label>
                  <input type="number" required className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.availableStock} onChange={e => setFormData({...formData, availableStock: Number(e.target.value)})} />
                </div>
                <div className="flex items-center pt-6">
                  <label className="flex items-center gap-3 cursor-pointer">
