                  </label>
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1 uppercase tracking-tighter">URL de l'image</label>
                <input type="text" required className="w-full px-4 py-2 border border-gray-200 rounded-md shadow-sm" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} />
