    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) navigate('/login');
      else {
        setUser(currentUser);
        loadData();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  const loadData = async () => {
    setLoading(true);
    const [p, s] = await Promise.all([getProducts(), getSales()]);
    setProducts(p);
    setSales(s);
    setLoading(false);
  };

