    e.preventDefault();
    if (packItems.length === 0) return;
    const cost = packItems.reduce((acc, i) => acc + (i.unitCost * i.quantity), 0);
    try {
      await addProductToDb({
        name: formData.name,
        description: formData.description,
        image: formData.image,
        purchasePrice: cost,
        salePrice: Number(formData.salePrice),
        category: 'pack',
        packItems,
        stock: 0,
        totalSold: 0
