           <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl p-10 max-h-[90vh] overflow-y-auto">
             <div className="flex justify-between items-center mb-6"><h2 className="text-2xl font-bold">Création de Pack</h2><button onClick={() => setIsAddPackOpen(false)} className="p-2 hover:bg-slate-100 rounded-full"><XIcon className="w-5 h-5"/></button></div>
             <div className="bg-amber-50 p-5 rounded-2xl border border-amber-100 mb-8 flex gap-4 items-center"><LayersIcon className="w-6 h-6 text-amber-600"/><p className="text-sm text-amber-800 font-medium">Regroupez vos produits pour créer des offres attractives.</p></div>
             <form onSubmit={handleAddPack} className="space-y-6">
                <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Nom de l'offre</label><input type="text" required placeholder="Ex: Pack Hiver Complet" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase block mb-2">Ajouter des produits</label>
                  <div className="border border-slate-200 rounded-2xl overflow-hidden mb-4 bg-white shadow-sm">
                    <div className="p-3 bg-slate-50 border-b flex items-center gap-2"><SearchIcon className="w-4 h-4 text-slate-400"/><input type="text" placeholder="Chercher..." className="bg-transparent text-sm w-full outline-none" value={packSearch} onChange={e => setPackSearch(e.target.value)}/></div>
                    <div className="max-h-40 overflow-y-auto p-2 space-y-1">
                      {products.filter(p => p.name.toLowerCase().includes(packSearch.toLowerCase()) && p.category !== 'pack').map(p => (
                        <button key={p.id} type="button" onClick={() => setPackItems([...packItems, { productId: p.id, productName: p.name, quantity: 1, unitCost: p.purchasePrice }])} className="flex items-center gap-3 p-2 hover:bg-indigo-50 rounded-xl w-full text-left">
                          <img src={p.image} className="w-8 h-8 rounded-lg object-contain bg-white" alt="" /><span className="text-xs font-bold text-slate-700">{p.name}</span><PlusIcon className="w-3 h-3 ml-auto text-slate-400"/>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                {packItems.length > 0 && (
                  <div className="space-y-2">
                    {packItems.map((item, idx) => (
                      <div key={idx} className="flex items-center gap-3 bg-slate-50 p-2 rounded-xl border border-slate-100">
                        <span className="flex-1 text-xs font-bold truncate ml-2">{item.productName}</span>
                        <input type="number" min="1" className="w-12 text-center text-xs font-bold bg-white border rounded-lg p-1" value={item.quantity} onChange={e => { const newItems = [...packItems]; newItems[idx].quantity = Number(e.target.value); setPackItems(newItems); }} />
                        <button type="button" onClick={() => setPackItems(packItems.filter((_, i) => i !== idx))} className="text-rose-500 p-2"><XIcon className="w-4 h-4"/></button>
                      </div>
                    ))}
                  </div>
                )}
                <div className="grid grid-cols-2 gap-6 bg-slate-100 p-6 rounded-[2rem]">
                    <div><label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Coût total</label><p className="text-xl font-black">{packItems.reduce((acc, i) => acc + (i.unitCost * i.quantity), 0).toFixed(2)} DH</p></div>
                    <div><label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Prix vente Pack</label><input type="number" required className="w-full bg-white border border-amber-200 rounded-xl px-3 py-2 font-bold text-amber-600 outline-none" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} /></div>
                </div>
                <button type="submit" disabled={packItems.length === 0} className="w-full py-4 bg-amber-500 text-white rounded-2xl font-bold text-lg hover:bg-amber-600 transition-all shadow-xl shadow-amber-200">Lancer le Pack</button>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;

import React, { useState, useEffect, useMemo } from 'react';
import { onAuthStateChanged, signOut, User } from 'firebase/auth';
import { auth } from '../services/firebase';
import { Product, Sale, Stats, PackItem } from '../types';
import { useNavigate } from 'react-router-dom';
import Spinner from '../components/Spinner';
import { 
  getProducts, 
  getSales, 
  addProductToDb, 
  updateProductInDb, 
  deleteProductFromDb, 
  addSaleToDb 
} from '../services/store';

// --- Icons ---
const PackageIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>;
const PlusIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>;
const SearchIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>;
const LayersIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>;
const ShoppingCartIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" /></svg>;
const EditIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>;
const TrashIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const DollarSignIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M12 16V15" /></svg>;
const TrendingUpIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>;
const BoxIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10l8 4 8-4V7l-8-4-8 4zm8-4v10m8-10l-8 4m0 0L4 7" /></svg>;
const XIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>;

const StatCard = ({ title, value, icon, color, trend, isPositive }: { title: string, value: string, icon: any, color: string, trend: string, isPositive: boolean }) => {
  const colorMap: any = {
    indigo: 'bg-indigo-600 shadow-indigo-200',
    emerald: 'bg-emerald-500 shadow-emerald-200',
    blue: 'bg-blue-500 shadow-blue-200',
    amber: 'bg-amber-500 shadow-amber-200',
  };
  return (
    <div className="bg-white p-6 rounded-3xl border border-slate-200/60 shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start mb-4">
        <div className={`p-3 rounded-2xl text-white ${colorMap[color] || 'bg-slate-900'}`}>{icon}</div>
        <div className={`text-xs font-bold px-2 py-1 rounded-full ${isPositive ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
          {trend}
        </div>
      </div>
      <div>
        <p className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
        <p className="text-2xl font-black text-slate-800">{value}</p>
        <p className="text-[10px] text-slate-400 mt-1">vs mois dernier</p>
      </div>
    </div>
  );
};

const AdminPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [search, setSearch] = useState('');

  // Modals
  const [isAddProductOpen, setIsAddProductOpen] = useState(false);
  const [isAddPackOpen, setIsAddPackOpen] = useState(false);
  const [isSellOpen, setIsSellOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);

  // Selection
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [sellQty, setSellQty] = useState(1);
  const [packItems, setPackItems] = useState<PackItem[]>([]);
  const [packSearch, setPackSearch] = useState('');

  // Form Data
  const initialForm = { 
    name: '', 
    description: '', 
    image: '', 
    purchasePrice: 0, 
    salePrice: 0, 
    stock: 0, 
    isOrderBased: false,
    category: 'simple' as any 
  };
  const [formData, setFormData] = useState(initialForm);

  const navigate = useNavigate();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) navigate('/login');
      else {
        setUser(currentUser);
        loadData();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  const loadData = async () => {
    setLoading(true);
    const [p, s] = await Promise.all([getProducts(), getSales()]);
    setProducts(p);
    setSales(s);
    setLoading(false);
  };

  const handleLogout = () => signOut(auth).then(() => navigate('/login'));

  const stats: Stats = useMemo(() => {
    const revenue = sales.reduce((acc, s) => acc + (s.totalPrice || 0), 0);
    const profit = sales.reduce((acc, s) => acc + (s.profit || 0), 0);
    const totalSold = sales.reduce((acc, s) => acc + (s.quantity || 0), 0);
    const stockValue = products.reduce((acc, p) => acc + ((p.purchasePrice || 0) * (p.stock || 0)), 0);
    return { revenue, profit, totalSold, stockValue };
  }, [products, sales]);

  const filteredProducts = products.filter(p => p.name?.toLowerCase().includes(search.toLowerCase()));

  // Handlers
  const openAddModal = () => {
    setFormData(initialForm);
    setIsAddProductOpen(true);
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await addProductToDb({ ...formData, totalSold: 0 });
      setIsAddProductOpen(false);
      loadData();
    } catch (err: any) { alert("Erreur: " + err.message); }
  };

  const handleSell = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProduct) return;
    try {
      const saleData = {
        productId: selectedProduct.id,
        productName: selectedProduct.name,
        quantity: sellQty,
        totalPrice: sellQty * Number(selectedProduct.salePrice),
        profit: sellQty * (Number(selectedProduct.salePrice) - Number(selectedProduct.purchasePrice)),
        date: Date.now()
      };
      await addSaleToDb(saleData, selectedProduct.stock);
      setIsSellOpen(false);
      loadData();
    } catch (err: any) { alert(err.message); }
  };

  const openPackModal = () => {
    setFormData({ ...initialForm, category: 'pack' });
    setPackItems([]);
    setIsAddPackOpen(true);
  };

  const handleAddPack = async (e: React.FormEvent) => {
    e.preventDefault();
    if (packItems.length === 0) return;
    const cost = packItems.reduce((acc, i) => acc + (i.unitCost * i.quantity), 0);
    try {
      await addProductToDb({
        name: formData.name,
        description: formData.description,
        image: formData.image,
        purchasePrice: cost,
        salePrice: Number(formData.salePrice),
        category: 'pack',
        isOrderBased: formData.isOrderBased,
        packItems,
        stock: 0,
        totalSold: 0
      });
      setIsAddPackOpen(false);
      loadData();
    } catch (err: any) { alert(err.message); }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Supprimer ce produit ?")) {
      await deleteProductFromDb(id);
      loadData();
    }
  };

  if (loading) return <Spinner />;

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0 z-[100]">
      {/* Sidebar */}
      <aside className="hidden md:flex flex-col w-20 lg:w-72 bg-white border-r border-slate-200 transition-all">
        <div className="h-20 flex items-center px-8 border-b border-slate-100">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg">M</div>
          <span className="font-bold text-xl text-slate-800 ml-4 hidden lg:block">Mercadona</span>
        </div>
        <div className="flex-1 py-8 px-4 space-y-2">
          <div className="px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4 hidden lg:block">Navigation</div>
          <button className="w-full flex items-center gap-3 px-4 py-3.5 bg-indigo-50 text-indigo-600 rounded-xl font-medium transition-all"><PackageIcon className="w-5 h-5" /><span className="hidden lg:block">Dashboard</span></button>
          <button onClick={openPackModal} className="w-full flex items-center gap-3 px-4 py-3.5 text-slate-500 hover:text-slate-900 hover:bg-slate-50 rounded-xl font-medium transition-all group">
            <LayersIcon className="w-5 h-5 group-hover:scale-110 transition-transform" />
            <span className="hidden lg:block">Nouveau Pack</span>
          </button>
        </div>
        <div className="p-4 border-t border-slate-100">
          <button onClick={handleLogout} className="w-full flex items-center justify-center lg:justify-start gap-3 px-4 py-3 text-slate-400 hover:text-rose-600 transition-all"><XIcon className="w-5 h-5" /><span className="hidden lg:block">Déconnexion</span></button>
        </div>
      </aside>

      {/* Main */}
      <main className="flex-1 flex flex-col h-full overflow-hidden bg-[#F8FAFC]">
        <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-20">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-bold text-slate-800">Vue d'ensemble</h2>
             <span className="px-3 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full uppercase">Pro</span>
          </div>
          <div className="flex items-center gap-4 flex-1 justify-end max-w-2xl">
            <div className="relative w-full max-w-md hidden sm:block">
              <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input type="text" placeholder="Rechercher (Cmd+K)" value={search} onChange={e => setSearch(e.target.value)} className="w-full pl-11 pr-4 py-2.5 bg-slate-100 border-none rounded-xl text-sm focus:bg-white focus:ring-2 focus:ring-indigo-100 transition-all" />
            </div>
            <button onClick={openAddModal} className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white text-sm font-semibold rounded-xl hover:bg-slate-800 transition-all shadow-md active:scale-95"><PlusIcon className="w-4 h-4" /><span>Produit</span></button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 pb-32">
          <div className="mb-8">
            <h1 className="text-2xl font-bold text-slate-900">Bonjour 👋</h1>
            <p className="text-slate-500 text-sm">Voici ce qui se passe dans votre stock aujourd'hui.</p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
            <StatCard title="Revenu Total" value={`${stats.revenue.toFixed(2)} DH`} icon={<DollarSignIcon className="w-5 h-5"/>} color="indigo" trend="+12.5%" isPositive={true}/>
            <StatCard title="Bénéfice Net" value={`${stats.profit.toFixed(2)} DH`} icon={<TrendingUpIcon className="w-5 h-5"/>} color="emerald" trend="+8.2%" isPositive={true} />
            <StatCard title="Ventes Totales" value={`${stats.totalSold}`} icon={<ShoppingCartIcon className="w-5 h-5"/>} color="blue" trend="+24" isPositive={true} />
            <StatCard title="Valeur Stock" value={`${stats.stockValue.toFixed(2)} DH`} icon={<BoxIcon className="w-5 h-5"/>} color="amber" trend="-2.4%" isPositive={false} />
          </div>

          <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200/60 overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-lg font-bold text-slate-800 tracking-tight">Inventaire</h3>
            </div>
            <div className="p-6">
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
                {filteredProducts.map(product => (
                  <div key={product.id} className="group flex flex-col bg-white border border-slate-100 rounded-3xl p-3 hover:shadow-xl transition-all relative overflow-hidden">
                    <div className="relative aspect-square rounded-2xl overflow-hidden bg-slate-50 mb-3">
                       <img src={product.image} className="w-full h-full object-contain p-2 group-hover:scale-110 transition-transform duration-500" alt="" />
                       <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                          <button onClick={() => { setSelectedProduct(product); setSellQty(1); setIsSellOpen(true); }} className="p-2.5 bg-white text-emerald-600 rounded-full hover:scale-110 shadow-lg"><ShoppingCartIcon className="w-4 h-4"/></button>
                          <button onClick={() => { setSelectedProduct(product); setIsEditOpen(true); setFormData({...product} as any); }} className="p-2.5 bg-white text-amber-500 rounded-full hover:scale-110 shadow-lg"><EditIcon className="w-4 h-4"/></button>
                          <button onClick={() => handleDelete(product.id)} className="p-2.5 bg-white text-rose-500 rounded-full hover:scale-110 shadow-lg"><TrashIcon className="w-4 h-4"/></button>
                       </div>
                       {product.category === 'pack' && <span className="absolute top-2 left-2 bg-indigo-600 text-white text-[8px] font-bold px-2 py-0.5 rounded-full uppercase">Pack</span>}
                       {product.isOrderBased && <span className="absolute top-2 right-2 bg-amber-500 text-white text-[8px] font-bold px-2 py-0.5 rounded-full uppercase">Commande</span>}
                    </div>
                    <div className="flex-1 flex flex-col">
                       <h4 className="font-bold text-slate-800 text-[11px] leading-tight mb-2 line-clamp-2">{product.name}</h4>
                       <div className="mt-auto flex items-end justify-between">
                          <div><div className="text-[8px] text-slate-400 font-bold uppercase">Prix</div><div className="font-black text-indigo-600 text-xs">{(product.salePrice || 0).toFixed(2)}</div></div>
                          <div className={`text-[9px] font-bold px-1.5 py-0.5 rounded-lg ${product.stock > 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                             {product.isOrderBased ? '∞' : product.stock}
                          </div>
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* --- Modals --- */}
      {isSellOpen && selectedProduct && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 animate-fade-in-scale">
            <div className="flex justify-between items-center mb-8">
                <h2 className="text-xl font-bold">Nouvelle Vente</h2>
                <button onClick={() => setIsSellOpen(false)} className="p-2 hover:bg-slate-100 rounded-full"><XIcon className="w-5 h-5"/></button>
            </div>
            <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-3xl mb-8">
                <img src={selectedProduct.image} className="w-16 h-16 rounded-2xl object-contain bg-white shadow-sm" alt=""/>
                <div><h3 className="font-bold text-slate-900 text-sm">{selectedProduct.name}</h3><p className="text-[10px] font-bold text-slate-400">Stock: {selectedProduct.isOrderBased ? 'Illimité (Sur Commande)' : selectedProduct.stock}</p></div>
            </div>
            <div className="flex items-center justify-center gap-8 mb-10">
                <button onClick={() => setSellQty(Math.max(1, sellQty-1))} className="w-12 h-12 rounded-full border border-slate-200 flex items-center justify-center text-xl hover:border-indigo-600 transition-colors">-</button>
                <span className="text-4xl font-black">{sellQty}</span>
                <button onClick={() => setSellQty(selectedProduct.isOrderBased ? sellQty + 1 : Math.min(selectedProduct.stock, sellQty+1))} className="w-12 h-12 rounded-full border border-slate-200 flex items-center justify-center text-xl hover:border-indigo-600 transition-colors">+</button>
            </div>
            <div className="bg-slate-900 p-6 rounded-3xl text-white flex justify-between items-center mb-6">
                <span className="text-sm font-bold text-slate-400 uppercase">Total</span>
                <span className="text-3xl font-black">{(selectedProduct.salePrice * sellQty).toFixed(2)} <span className="text-lg font-normal">DH</span></span>
            </div>
            <button onClick={handleSell} className="w-full py-4 bg-emerald-500 text-white rounded-2xl font-bold text-lg hover:bg-emerald-600 transition-all shadow-lg shadow-emerald-200">Valider l'encaissement</button>
          </div>
        </div>
      )}

      {(isAddProductOpen || isEditOpen) && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
           <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl p-10 max-h-[90vh] overflow-y-auto animate-fade-in-scale">
             <div className="flex justify-between items-center mb-8">
                <h2 className="text-2xl font-bold">{isEditOpen ? 'Modifier' : 'Ajouter au stock'}</h2>
                <button onClick={() => { setIsAddProductOpen(false); setIsEditOpen(false); }} className="p-2 hover:bg-slate-100 rounded-full"><XIcon className="w-5 h-5"/></button>
             </div>
             <form onSubmit={isEditOpen ? (e) => { e.preventDefault(); updateProductInDb(selectedProduct!.id, formData).then(() => { setIsEditOpen(false); loadData(); }); } : handleAddProduct} className="space-y-6">
                <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Nom du produit</label><input type="text" required className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-100" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
                <div className="grid grid-cols-2 gap-6">
                  <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Prix Achat (DH)</label><input type="number" step="0.01" required className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={formData.purchasePrice} onChange={e => setFormData({...formData, purchasePrice: Number(e.target.value)})} /></div>
                  <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Prix Vente (DH)</label><input type="number" step="0.01" required className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} /></div>
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Stock</label><input type="number" required className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none disabled:opacity-50" disabled={formData.isOrderBased} value={formData.stock} onChange={e => setFormData({...formData, stock: Number(e.target.value)})} /></div>
                  <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Image URL</label><input type="text" required className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} /></div>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <input type="checkbox" id="isOrderBased" className="w-5 h-5 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer" checked={formData.isOrderBased} onChange={e => setFormData({...formData, isOrderBased: e.target.checked})} />
                    <label htmlFor="isOrderBased" className="text-sm font-bold text-slate-700 cursor-pointer uppercase tracking-tighter">Produit "Sur Commande" (Stock Illimité)</label>
                </div>
                <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold text-lg hover:bg-slate-800 transition-all mt-6 shadow-xl shadow-slate-900/20">{isEditOpen ? 'Enregistrer' : 'Ajouter le Produit'}</button>
             </form>
           </div>
        </div>
      )}

      {isAddPackOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
           <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl p-10 max-h-[90vh] overflow-y-auto animate-fade-in-scale">
             <div className="flex justify-between items-center mb-6"><h2 className="text-2xl font-bold">Création de Pack</h2><button onClick={() => setIsAddPackOpen(false)} className="p-2 hover:bg-slate-100 rounded-full"><XIcon className="w-5 h-5"/></button></div>
             <div className="bg-amber-50 p-5 rounded-2xl border border-amber-100 mb-8 flex gap-4 items-center"><LayersIcon className="w-6 h-6 text-amber-600"/><p className="text-sm text-amber-800 font-medium">Regroupez vos produits pour créer des offres attractives.</p></div>
             <form onSubmit={handleAddPack} className="space-y-6">
                <div><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Nom de l'offre</label><input type="text" required placeholder="Ex: Pack Hiver Complet" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-amber-100" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase block mb-2">Ajouter des produits</label>
                  <div className="border border-slate-200 rounded-2xl overflow-hidden mb-4 bg-white shadow-sm">
                    <div className="p-3 bg-slate-50 border-b flex items-center gap-2"><SearchIcon className="w-4 h-4 text-slate-400"/><input type="text" placeholder="Chercher..." className="bg-transparent text-sm w-full outline-none" value={packSearch} onChange={e => setPackSearch(e.target.value)}/></div>
                    <div className="max-h-40 overflow-y-auto p-2 space-y-1">
                      {products.filter(p => p.name.toLowerCase().includes(packSearch.toLowerCase()) && p.category !== 'pack').map(p => (
                        <button key={p.id} type="button" onClick={() => setPackItems([...packItems, { productId: p.id, productName: p.name, quantity: 1, unitCost: p.purchasePrice }])} className="flex items-center gap-3 p-2 hover:bg-indigo-50 rounded-xl w-full text-left">
                          <img src={p.image} className="w-8 h-8 rounded-lg object-contain bg-white" alt="" /><span className="text-xs font-bold text-slate-700">{p.name}</span><PlusIcon className="w-3 h-3 ml-auto text-slate-400"/>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                {packItems.length > 0 && (
                  <div className="space-y-2">
                    {packItems.map((item, idx) => (
                      <div key={idx} className="flex items-center gap-3 bg-slate-50 p-2 rounded-xl border border-slate-100">
                        <span className="flex-1 text-xs font-bold truncate ml-2">{item.productName}</span>
                        <input type="number" min="1" className="w-12 text-center text-xs font-bold bg-white border rounded-lg p-1" value={item.quantity} onChange={e => { const newItems = [...packItems]; newItems[idx].quantity = Number(e.target.value); setPackItems(newItems); }} />
                        <button type="button" onClick={() => setPackItems(packItems.filter((_, i) => i !== idx))} className="text-rose-500 p-2"><XIcon className="w-4 h-4"/></button>
                      </div>
                    ))}
                  </div>
                )}
                <div className="flex items-center gap-3 bg-amber-50 p-4 rounded-2xl border border-amber-100">
                    <input type="checkbox" id="isPackOrderBased" className="w-5 h-5 rounded text-amber-600 focus:ring-amber-500 cursor-pointer" checked={formData.isOrderBased} onChange={e => setFormData({...formData, isOrderBased: e.target.checked})} />
                    <label htmlFor="isPackOrderBased" className="text-sm font-bold text-amber-800 cursor-pointer uppercase tracking-tighter">Pack "Sur Commande" (Non présent en stock physique)</label>
                </div>
                <div className="grid grid-cols-2 gap-6 bg-slate-100 p-6 rounded-[2rem]">
                    <div><label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Coût total</label><p className="text-xl font-black">{packItems.reduce((acc, i) => acc + (i.unitCost * i.quantity), 0).toFixed(2)} DH</p></div>
                    <div><label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Prix vente Pack</label><input type="number" required className="w-full bg-white border border-amber-200 rounded-xl px-3 py-2 font-bold text-amber-600 outline-none" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} /></div>
                </div>
                <button type="submit" disabled={packItems.length === 0} className="w-full py-4 bg-amber-500 text-white rounded-2xl font-bold text-lg hover:bg-amber-600 transition-all shadow-xl shadow-amber-200 active:scale-95">Lancer le Pack</button>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;
